
const enum ENV {
    local = 'local',
    development = 'development',
    test = 'test',
    production = 'production',
}

const SSO_API_URL_MAP = {
    [ENV.local]: 'https://sso.dev.spotterio.com',
    [ENV.development]: 'https://sso.dev.spotterio.com',
    [ENV.test]: 'https://sso.tst.spotterio.com',
    [ENV.production]: 'https://sso.spotterio.com'
}

const SSO_TOKEN = 'Authentication-Token'
export const SessionKeys = 'spotter_token'

export const AuthErrorCode = new Set([401, 
    4_010_000, 
    4_010_001, 
    4_010_002, 
    4_010_003, 
    4_010_004,
    -1, // //-1～-7 sso框架的
    -2,
    -3,
    -4,
    -5,
    -6,
    -7,
])

export const PermissionErrorCode = new Set([403, 403_001]);

interface SsoParams {
    env: keyof typeof ENV,
    appCode: string,
    loginPath?: string,
    ssoUrl?: string
}

/**
 * 纯前端使用
 */
export class SSOSDK {
    private env: keyof typeof ENV  = 'production';
    private appCode  = '';
    private readonly SSO_TICKET = 'spotter_sso_ticket';
    private readonly SPOTTER_SSO_REDIRECT_COUNT = 'spotter_sso_redirect_count'
    private readonly SPOTTER_SSO_START_TIME = 'spotter_sso_start_time'
    private loginPath:string | undefined = ''; // 登录后指定跳转页面地址
    private ssoUrl:string | undefined = ''; 

    constructor({
        env,
        ssoUrl,
        appCode,
        loginPath
    }: SsoParams){
        this.env = env;
        this.appCode = appCode;
        this.loginPath = loginPath;
        this.ssoUrl = ssoUrl || SSO_API_URL_MAP[env];
    }

    async login() {
        console.log('ssoUrl', this.ssoUrl);
        const ticket = this.getLastSpotterSsoTicket(window.location.search)
        const noTicket = this.removeQueryParam(this.getRedirectUrl(), this.SSO_TICKET)
        if (ticket) {
            try {
            const { code, msg, data } = await this.doLoginByTicket(ticket)
            if (code === 200) {
                localStorage.setItem(SSO_TOKEN, data?.token)
                window.history.replaceState('', '', noTicket)
            }
            else {
                throw new Error(msg)
            }
            }
            catch (error: any) {
                throw new Error(error?.msg || 'sso login error')
            }
        }
        const ticketToken = localStorage.getItem(SSO_TOKEN)
        if (ticketToken) {
            try {
            const { code, msg } = await this.checkLogin(ticketToken)
            if (code === 200)
                window.history.replaceState('', '', noTicket)
            else
                throw new Error(msg)
            }
            catch (error: any) {
                throw new Error(error?.msg || 'sso check login error')
            }
        }
    }

    private async doLoginByTicket(ticket: string) {
        const res = (await (await fetch(`${this.ssoUrl}/sso/client/doLoginByTicket`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              ticket,
              appCode: this.appCode,
            }),
          })).json())
          return res;
    }
    private async checkLogin(token: string) {
        const res = (await (await fetch(`${this.ssoUrl}/sso/client/isLogin`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            token,
          }),
        })).json())
        return res
    }
    getLastSpotterSsoTicket(url: string) {
        const params = new URLSearchParams(url)
        let lastValue = null
        params.getAll(this.SSO_TICKET).forEach((value) => {
          lastValue = value
        })
        return lastValue
    }
    removeQueryParam(url: string | URL, param: string) {
        const urlObj = new URL(url)
        const searchParams = new URLSearchParams(urlObj.search)
        searchParams.delete(param)
        urlObj.search = searchParams.toString()
        return urlObj.toString()
    }
    redirectToSSO() {
        window.location.href = `${this.ssoUrl}/sso/auth?redirect=${encodeURIComponent(this.getRedirectUrl())}&appCode=${this.appCode}`
    }
    redirectToSSOLogout() {
        localStorage.removeItem(SSO_TOKEN)
        localStorage.removeItem(this.SPOTTER_SSO_REDIRECT_COUNT)
        window.location.href = `${this.ssoUrl}/sso/client/signout?back=${
        encodeURIComponent(this.getRedirectUrl())}&appCode=${this.appCode}`
    }
    redirectWithLimit(limit: number = 10): void {
        const redirectCount: number = Number(sessionStorage.getItem(this.SPOTTER_SSO_REDIRECT_COUNT)) || 0
      
        const lastTime = Number(sessionStorage.getItem(this.SPOTTER_SSO_START_TIME)) || 0
      
        if (redirectCount >= limit && Date.now() - lastTime < 2000) {
          sessionStorage.setItem(this.SPOTTER_SSO_START_TIME, String(Date.now()))
          throw new Error('sso 重定向过多，请退出重新登录')
        }
        if (Date.now() - lastTime < 1000)
          sessionStorage.setItem(this.SPOTTER_SSO_REDIRECT_COUNT, String(redirectCount + 1))
      
        sessionStorage.setItem(this.SPOTTER_SSO_START_TIME, String(Date.now()))
        this.redirectToSSO()
    }
    getSSOToken() {
        return SSO_TOKEN
    }
    private getRedirectUrl() {
        if(this.loginPath) {
            const url = `${window.location.protocol}//${window.location.hostname}:${window.location.port}${this.loginPath}`;
            return url
        } else {
            return window.location.href
        }
    }
}

/**
 * 存在前后端使用
 */
export class SSOSDKClient {
    private env: keyof typeof ENV  = 'production';
    private readonly SSO_TICKET = 'spotter_sso_ticket';
    private appCode  = '';
    constructor({
        env,
        appCode
    }:SsoParams) {
        this.env = env;
        this.appCode = appCode;
    }
    login(){
        window.location.href = `${
            SSO_API_URL_MAP[this.env]
        }/sso/auth?redirect=${encodeURIComponent(
            this.removeQueryParam(window.location.href, this.SSO_TICKET),
        )}&appCode=${this.appCode}`;  
    }
    logout() {
        const cookieKey = SessionKeys;
        console.log('清除cookie前', document.cookie);
        this.clearCookie(cookieKey);
        console.log('清除cookie后', document.cookie);
        window.location.replace(
            `${window.location.origin}/api/v1/sso/logout?client=${encodeURIComponent(
                this.removeQueryParam(window.location.href, this.SSO_TICKET),
            )}`,
        );
    }
    clearCookie(name: string) {
        document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;`;
    }
    removeQueryParam = (url: string | URL, param: string) => {
        const urlObj = new URL(url);
        const searchParams = new URLSearchParams(urlObj.search);
        searchParams.delete(param);
        urlObj.search = searchParams.toString();
        return urlObj.toString();
    };
    getCookie() {
        const cookieKey = SessionKeys;
        const arr = document.cookie.split('; ');
        for (const element of arr) {
            const arr2 = element.split('=');
            if (arr2[0].trim() === cookieKey) {
                return arr2[1];
            }
        }
        return '';
    }
}